body.script:
/* =========================================
   0. KONTROL LOGIKA PRELOADER
   ========================================= */
document.body.classList.add('loading-active');
window.addEventListener('DOMContentLoaded', () => {
    const preloader = document.getElementById('preloader');
    const loaderText = document.getElementById('loaderText');
    const textString = loaderText.textContent.trim();
    loaderText.textContent = '';
    textString.split('').forEach((char, index) => {
        const span = document.createElement('span');
        span.textContent = char;
        span.classList.add('loader-letter');
        span.style.animationDelay = `${0.4 + (index * 0.08)}s`;
        loaderText.appendChild(span);
    });
    setTimeout(() => {
        preloader.style.opacity = '0';
        preloader.style.visibility = 'hidden';
        document.body.classList.remove('loading-active');
    }, 2400); 
});

/* =========================================
   1. LOGIKA KURSOR ASAP BERWARNA
   ========================================= */
const smokeCanvas = document.createElement('canvas');
smokeCanvas.id = 'smokeCanvas';
document.body.appendChild(smokeCanvas);
const smokeCtx = smokeCanvas.getContext('2d');
function resizeSmoke() { smokeCanvas.width = window.innerWidth; smokeCanvas.height = window.innerHeight; }
window.addEventListener('resize', resizeSmoke);
resizeSmoke();

let smokeParticles = [];
let mouse = { x: -100, y: -100 };
const smokeColors = ['168, 85, 247', '59, 130, 246', '236, 72, 153'];

window.addEventListener('mousemove', (e) => {
    mouse.x = e.clientX; mouse.y = e.clientY;
    for (let i = 0; i < 3; i++) { smokeParticles.push(new SmokeParticle(mouse.x, mouse.y)); }
});

class SmokeParticle {
    constructor(x, y) {
        this.x = x + (Math.random() * 10 - 5); this.y = y + (Math.random() * 10 - 5);
        this.size = Math.random() * 8 + 4; this.vx = (Math.random() - 0.5) * 1.5; this.vy = (Math.random() - 1) * 2;
        this.life = 1; this.decay = Math.random() * 0.03 + 0.015; 
        this.color = smokeColors[Math.floor(Math.random() * smokeColors.length)];
    }
    update() { this.x += this.vx; this.y += this.vy; this.size += 0.3; this.life -= this.decay; }
    draw() {
        smokeCtx.beginPath(); smokeCtx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        smokeCtx.fillStyle = `rgba(${this.color}, ${this.life * 0.4})`; smokeCtx.fill();
    }
}
function animateSmoke() {
    requestAnimationFrame(animateSmoke);
    smokeCtx.clearRect(0, 0, smokeCanvas.width, smokeCanvas.height);
    for (let i = 0; i < smokeParticles.length; i++) {
        smokeParticles[i].update(); smokeParticles[i].draw();
        if (smokeParticles[i].life <= 0) { smokeParticles.splice(i, 1); i--; }
    }
}
animateSmoke();

window.addEventListener('mousedown', (e) => {
    const ripple = document.createElement('div');
    ripple.classList.add('ripple');
    ripple.style.left = (e.clientX - 10) + 'px'; ripple.style.top = (e.clientY - 10) + 'px';
    document.body.appendChild(ripple);
    setTimeout(() => { ripple.remove(); }, 600);
});

/* =========================================
   2. TEMA GELAP/TERANG + PERUBAHAN LOGO TOGGLE
   ========================================= */
const themeToggle = document.getElementById('themeToggle');
const html = document.documentElement;

const savedTheme = localStorage.getItem('theme') || 'dark';
html.setAttribute('data-theme', savedTheme);
updateThemeButton(savedTheme);

themeToggle.addEventListener('click', () => {
    const currentTheme = html.getAttribute('data-theme');
    const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
    html.setAttribute('data-theme', newTheme);
    localStorage.setItem('theme', newTheme);
    updateThemeButton(newTheme);
});

// BERUBAH: Fungsi diperbarui agar hanya mengganti logo FontAwesome (Tanpa Teks)
function updateThemeButton(theme) {
    themeToggle.innerHTML = theme === 'dark' ? '' : '';
}

/* =========================================
   3. ANIMASI SCROLL REVEAL
   ========================================= */
function reveal() {
    var reveals = document.querySelectorAll(".reveal");
    for (var i = 0; i < reveals.length; i++) {
        var windowHeight = window.innerHeight;
        var elementTop = reveals[i].getBoundingClientRect().top;
        var elementVisible = 100;
        if (elementTop < windowHeight - elementVisible) { reveals[i].classList.add("active"); }
    }
}
window.addEventListener("scroll", reveal);
reveal(); 

/* =========================================
   4. MUSIK OTOMATIS
   ========================================= */
const bgMusic = document.getElementById('bgMusic');
const musicToggle = document.getElementById('musicToggle');
let isMusicPlaying = false;

document.body.addEventListener('click', function initAudio() {
    if(!isMusicPlaying) {
        bgMusic.play().then(() => {
            isMusicPlaying = true;
            musicToggle.classList.add('playing');
            musicToggle.innerHTML = '🎶';
        }).catch(e => console.log("Menunggu audio...", e));
        document.body.removeEventListener('click', initAudio);
    }
}, { once: true });

musicToggle.addEventListener('click', (e) => {
    e.stopPropagation();
    if(isMusicPlaying) {
        bgMusic.pause(); isMusicPlaying = false;
        musicToggle.classList.remove('playing'); musicToggle.innerHTML = '🎵';
    } else {
        bgMusic.play(); isMusicPlaying = true;
        musicToggle.classList.add('playing'); musicToggle.innerHTML = '🎶';
    }
});

/* =========================================
   5. CANVAS TECH NETWORK
   ========================================= */
const canvas = document.getElementById('techCanvas');
const ctx = canvas.getContext('2d');
let particlesArray = [];

function resizeCanvas() { canvas.width = window.innerWidth; canvas.height = window.innerHeight; }
window.addEventListener('resize', resizeCanvas);
resizeCanvas();

class Particle {
    constructor(x, y, directionX, directionY, size, color) {
        this.x = x; this.y = y; this.directionX = directionX; this.directionY = directionY;
        this.size = size; this.color = color;
    }
    draw() { ctx.beginPath(); ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2, false); ctx.fillStyle = this.color; ctx.fill(); }
    update() {
        if (this.x > canvas.width || this.x < 0) this.directionX = -this.directionX;
        if (this.y > canvas.height || this.y < 0) this.directionY = -this.directionY;
        this.x += this.directionX; this.y += this.directionY; this.draw();
    }
}

function initCanvas() {
    particlesArray = [];
    let numberOfParticles = (canvas.height * canvas.width) / 12000;
    for (let i = 0; i < numberOfParticles; i++) {
        let size = (Math.random() * 2) + 1;
        let x = Math.random() * innerWidth; let y = Math.random() * innerHeight;
        let directionX = (Math.random() * 1.5) - 0.75; let directionY = (Math.random() * 1.5) - 0.75;
        let color = '#a855f7';
        particlesArray.push(new Particle(x, y, directionX, directionY, size, color));
    }
}

function connectParticles() {
    const maxDistance = 130;
    const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
    const r = isDark ? 168 : 59; const g = isDark ? 85 : 130; const b = isDark ? 247 : 246;

    for (let a = 0; a < particlesArray.length; a++) {
        for (let c = a; c < particlesArray.length; c++) {
            let dx = particlesArray[a].x - particlesArray[c].x; let dy = particlesArray[a].y - particlesArray[c].y;
            let distance = (dx * dx) + (dy * dy);
            if (distance < maxDistance * maxDistance) {
                let opacityValue = 1 - (distance / (maxDistance * maxDistance));
                ctx.strokeStyle = `rgba(${r}, ${g}, ${b}, ${opacityValue})`; ctx.lineWidth = 1;
                ctx.beginPath(); ctx.moveTo(particlesArray[a].x, particlesArray[a].y); ctx.lineTo(particlesArray[c].x, particlesArray[c].y); ctx.stroke();
            }
        }
    }
}

function animateCanvas() { requestAnimationFrame(animateCanvas); ctx.clearRect(0, 0, innerWidth, innerHeight); for (let i = 0; i < particlesArray.length; i++) { particlesArray[i].update(); } connectParticles(); }
initCanvas(); animateCanvas();
